// Extract competitor position from SERP results
const input = $input.first().json;
const competitorDomain = $('Batch Keywords').first().json.competitor_domain;
const keyword = $('Batch Keywords').first().json.keyword;
const keywordId = $('Batch Keywords').first().json.keyword_id;
const competitorId = $('Batch Keywords').first().json.competitor_id;

const tasks = input.tasks || [];
const items = tasks[0]?.result?.[0]?.items || [];

// Find competitor in results
let position = null;
let url = null;
let hasFeatureSnippet = false;
let hasLocalPack = false;

for (const item of items) {
  if (item.type === 'featured_snippet' && item.domain?.includes(competitorDomain)) {
    hasFeatureSnippet = true;
  }
  if (item.type === 'local_pack') {
    hasLocalPack = true;
  }
  if (item.type === 'organic' && item.domain?.includes(competitorDomain)) {
    position = item.rank_absolute;
    url = item.url;
    break;
  }
}

return [{
  json: {
    collected_date: new Date().toISOString().split('T')[0],
    competitor_id: competitorId,
    competitor_domain: competitorDomain,
    keyword_id: keywordId,
    keyword: keyword,
    position: position,
    url: url,
    has_featured_snippet: hasFeatureSnippet,
    has_local_pack: hasLocalPack
  }
}];
